insert into public.products (id, name, brand, description, category, variants, images, position) values
  ('1', ' 9 AM DIVE EDP 100ML', 'AFNAN', '9am Dive de Afnan es una fragancia de la familia olfativa Aromática Acuática para Hombres y Mujeres. 9am Dive se lanzó en 2022. La Nariz detrás de esta fragrancia es Imran Fazlani. Las Notas de Salida son limón (lima ácida), menta, grosellas negras y pimienta rosa; las Notas de Corazón son manzana, cedro y incienso; las Notas de Fondo son jengibre, sándalo, pachulí y jazmín.', 'unisex', '[{"size":"5ml","price":8200},{"size":"100ml","price":81800}]'::jsonb, '["/images/products/9%20AM%20DIVE(2).jpg","/images/products/9%20AM%20DIVE(1).jpg","/images/products/9%20AM%20DIVE.jpg"]'::jsonb, 0),
  ('2', ' 9 PM MASC EDP 100ML', 'AFNAN', '9pm de Afnan es una fragancia de la familia olfativa Oriental Vainilla para Hombres. 9pm se lanzó en 2020. Las Notas de Salida son manzana, canela, lavanda silvestre y bergamota; las Notas de Corazón son flor de azahar del naranjo y lirio de los valles (muguete); las Notas de Fondo son vainilla, haba tonka, ámbar y pachulí.', 'masculino', '[{"size":"5ml","price":7400},{"size":"100ml","price":73700}]'::jsonb, '["/images/products/AFNAN%209%20PM%203.jpg","/images/products/AFNAN%209%20PM%205.jpg","/images/products/AFNAN%209%20PM.jpg"]'::jsonb, 1),
  ('3', ' 9 PM REBEL EDP 100ML', 'AFNAN', '9 PM Rebel de Afnan es una fragancia de la familia olfativa Aromática Frutal para Hombres y Mujeres. Esta fragrancia es nueva. 9 PM Rebel se lanzó en 2024. La Nariz detrás de esta fragrancia es Gaël Montero. Las Notas de Salida son piña, manzana Granny Smith y mandarina; las Notas de Corazón son musgo de roble, cedro y vainilla; las Notas de Fondo son Madera seca, ámbar gris, caramelo y almizcle.', 'unisex', '[{"size":"5ml","price":9700},{"size":"100ml","price":96800}]'::jsonb, '["/images/products/9%20PM%20REBEL(1).jpg","/images/products/9%20PM%20REBEL(2).jpg","/images/products/9%20PM%20REBEL(3).JPG"]'::jsonb, 2),
  ('4', 'AMBER OUD DUBAI NIGHT EDP 100ML', 'AL HARAMAIN', 'Amber Oud Dubai Night de Al Haramain es una fragancia de la familia olfativa Oriental Amaderada para Hombres. Esta fragrancia es nueva. Amber Oud Dubai Night se lanzó en 2024. Las Notas de Salida son azafrán, bergamota y elemí; las Notas de Corazón son madera de oud, rosa de Bulgaria (rosa Damascena de Bulgaria) y lirio de los valles (muguete); las Notas de Fondo son haba tonka, ámbar, almizcle blanco y musgo de roble.', 'masculino', '[{"size":"5ml","price":11700},{"size":"100ml","price":116600}]'::jsonb, '["/images/products/ChatGPT%20Image%2014%20jun%202026%2003_28_13%20p.m.png"]'::jsonb, 3),
  ('5', 'AMBER OUD GOLD EDITION EDP 120ML', 'AL HARAMAIN', 'Amber Oud Gold Edition de Al Haramain Perfumes es una fragancia de la familia olfativa Oriental Vainilla para Hombres y Mujeres. Amber Oud Gold Edition se lanzó en 2024. Las Notas de Salida son bergamota y notas verdes; las Notas de Corazón son melón, piña, ámbar y Acorde goloso; las Notas de Fondo son vainilla, almizcle y notas amaderadas.', 'unisex', '[{"size":"5ml","price":10600},{"size":"120ml","price":126800}]'::jsonb, '["/images/products/AL%20HARAMAIN%20AMBER%20OUD%20GOLD%20EDITION(1).JPG","/images/products/AL%20HARAMAIN%20AMBER%20OUD%20GOLD%20EDITION(2).JPG","/images/products/AL%20HARAMAIN%20AMBER%20OUD%20GOLD%20EDITION(3).jpg"]'::jsonb, 4),
  ('6', 'SABAH AL WARD 100ML', 'AL WATANIAH', 'Sabah Al Ward de Al Wataniah es una fragancia de la familia olfativa Oriental Floral para Mujeres. Las Notas de Salida son pimienta rosa y mandarina; las Notas de Corazón son vaina de cacao, flor de azahar del naranjo y jazmín sambac (sampaguita); las Notas de Fondo son vainilla, haba tonka y pachulí.', 'femenino', '[{"size":"5ml","price":4600},{"size":"100ml","price":46300}]'::jsonb, '["/images/products/AL%20WATANIAH%20DAR%20AL%20WARD(1).jpg","/images/products/AL%20WATANIAH%20DAR%20AL%20WARD(2).jpg","/images/products/AL%20WATANIAH%20DAR%20AL%20WARD.jpg"]'::jsonb, 5),
  ('7', 'CLUB DE NUIT ICONIC EDP 105ML', 'ARMAF', 'Club de Nuit Blue Iconic de Armaf es una fragancia de la familia olfativa para Hombres. Club de Nuit Blue Iconic se lanzó en 2022. Las Notas de Salida son toronja (pomelo), limón (lima ácida), menta, pimienta rosa y cilantro; las Notas de Corazón son jengibre, melón, jazmín y nuez moscada; las Notas de Fondo son notas amaderadas, incienso, sándalo, ámbar, cedro, pachulí y ládano.', 'masculino', '[{"size":"5ml","price":10800},{"size":"105ml","price":113300}]'::jsonb, '["/images/products/CLUB%20DE%20NUIT%20ICONIC(1).jpg","/images/products/CLUB%20DE%20NUIT%20ICONIC(2).jpg","/images/products/CLUB%20DE%20NUIT%20ICONIC(3).jpg"]'::jsonb, 6),
  ('8', 'CLUB DE NUIT INTENSE MAN EDT 105ML', 'ARMAF', 'Club de Nuit Intense Man de Armaf es una fragancia de la familia olfativa Amaderada Especiada para Hombres. Club de Nuit Intense Man se lanzó en 2015. Las Notas de Salida son limón (lima ácida), piña, bergamota, grosellas negras y manzana; las Notas de Corazón son abedul, jazmín y rosa; las Notas de Fondo son almizcle, ámbar gris, pachulí y vainilla.', 'masculino', '[{"size":"5ml","price":9100},{"size":"105ml","price":96000}]'::jsonb, '["/images/products/CLUB%20DE%20NUIT%20INTENSE%20MAN(1).jpg","/images/products/CLUB%20DE%20NUIT%20INTENSE%20MAN.jpg"]'::jsonb, 7),
  ('9', 'CLUB DE NUIT MILESTONE EDP 105ML', 'ARMAF', 'Club de Nuit Milestone de Armaf es una fragancia de la familia olfativa Almizcle Amaderado Floral para Hombres y Mujeres. Club de Nuit Milestone se lanzó en 2019. Las Notas de Salida son notas marinas, Frutas rojas y bergamota; las Notas de Corazón son violeta, maderas blancas y sándalo; las Notas de Fondo son almizcle, ambroxan y vetiver.', 'unisex', '[{"size":"5ml","price":8300},{"size":"100ml","price":87500}]'::jsonb, '["/images/products/CLUB%20DE%20NUIT%20MILESTONE..jpg","/images/products/CLUB%20DE%20NUIT%20MILESTONE.jpg"]'::jsonb, 8),
  ('10', 'CLUB DE NUIT SILLAGE EDP 105ML', 'ARMAF', 'Club de Nuit Sillage de Armaf es una fragancia de la familia olfativa Almizcle Floral Amaderado para Hombres y Mujeres. Club de Nuit Sillage se lanzó en 2020. Las Notas de Salida son bergamota, limón (lima ácida), lima (limón verde), grosellas negras, hojas de violeta y jengibre; las Notas de Corazón son rosa, iris y jazmín; las Notas de Fondo son ambroxan, almizcle, sándalo y cedro.', 'unisex', '[{"size":"5ml","price":8800},{"size":"100ml","price":92600}]'::jsonb, '["/images/products/CLUB%20DE%20NUIT%20SILAGE(1).jpg","/images/products/CLUB%20DE%20NUIT%20SILAGE(2).jpg","/images/products/CLUB%20DE%20NUIT%20SILAGE..JPG"]'::jsonb, 9),
  ('11', 'CLUB DE NUIT UNTOLD EDP 105ML', 'ARMAF', 'Club de Nuit Untold de Armaf es una fragancia de la familia olfativa para Hombres y Mujeres. Club de Nuit Untold se lanzó en 2022. Las Notas de Salida son azafrán y jazmín; las Notas de Corazón son Amberwood y ámbar gris; las Notas de Fondo son resina de abeto y cedro.', 'unisex', '[{"size":"5ml","price":10100},{"size":"100ml","price":106300}]'::jsonb, '[]'::jsonb, 10),
  ('12', 'CLUB DE NUIT URBAN MAN ELIXIR EDP 105ML', 'ARMAF', 'Club De Nuit Urban Elixir de Armaf es una fragancia de la familia olfativa para Hombres. Club De Nuit Urban Elixir se lanzó en 2022. Las Notas de Salida son bergamota, pimienta rosa, flor de azahar del naranjo y jazmín; las Notas de Corazón son lavanda, elemí, geranio, vetiver, azafrán y cempasúchil (tagete, clavelón); las Notas de Fondo son ambroxan, ámbar, cedro, pachulí y ládano.', 'masculino', '[{"size":"5ml","price":8500},{"size":"100ml","price":89200}]'::jsonb, '["/images/products/CLUB%20DE%20NUIT%20URBAN%20MAN%20ELIXIR(1).jpg","/images/products/CLUB%20DE%20NUIT%20URBAN%20MAN%20ELIXIR(2).jpg","/images/products/CLUB%20DE%20NUIT%20URBAN%20MAN%20ELIXIR.jpg"]'::jsonb, 11),
  ('13', 'CLUB DE NUIT WOMAN EDP 105ML', 'ARMAF', 'Club de Nuit Woman de Armaf es una fragancia de la familia olfativa Floral Frutal para Mujeres. Las Notas de Salida son naranja, bergamota, toronja (pomelo) y durazno (melocotón); las Notas de Corazón son rosa, jazmín, lichi y geranio; las Notas de Fondo son pachulí, almizcle, vainilla y vetiver.', 'femenino', '[{"size":"5ml","price":7500},{"size":"100ml","price":78800}]'::jsonb, '["/images/products/CLUB%20DE%20NUIT%20WOMAN(1).jpg","/images/products/CLUB%20DE%20NUIT%20WOMAN(2).jpg","/images/products/CLUB%20DE%20NUIT%20WOMAN.jpg"]'::jsonb, 12),
  ('14', 'ODYSSEY CANDEE EDP 100ML', 'ARMAF', 'Odyssey Candee de Armaf es una fragancia de la familia olfativa para Mujeres. Esta fragrancia es nueva. Odyssey Candee se lanzó en 2024. Las Notas de Salida son fresa, frambuesa, geranio, durazno (melocotón) y bergamota; las Notas de Corazón son caramelo, jazmín y maracuyá (fruta de la pasión); las Notas de Fondo son pachulí, almizcle y ámbar.', 'femenino', '[{"size":"5ml","price":6500},{"size":"100ml","price":65200}]'::jsonb, '["/images/products/ODYSSEY%20CANDEE(1).JPG","/images/products/ODYSSEY%20CANDEE(2).jpg","/images/products/ODYSSEY%20CANDEE.jpg"]'::jsonb, 13),
  ('15', 'ODYSSEY HOMME WHITE EDP 100ML ', 'ARMAF', 'Odyssey Homme White Edition de Armaf es una fragancia de la familia olfativa Oriental Fougère para Hombres. Las Notas de Salida son pimienta rosa, cardamomo y menta; las Notas de Corazón son salvia, Notas acuáticas y piña; las Notas de Fondo son Amberwood, vainilla y cedro.', 'masculino', '[{"size":"5ml","price":7200},{"size":"100ml","price":72000}]'::jsonb, '[]'::jsonb, 14),
  ('16', 'ODYSSEY LIMONI EDP 100ML', 'ARMAF', 'Odyssey Limoni Fresh de Armaf es una fragancia de la familia olfativa para Hombres y Mujeres. Esta fragrancia es nueva. Odyssey Limoni Fresh se lanzó en 2024. Las Notas de Salida son limón (lima ácida), naranja dulce, mandarina y bergamota; las Notas de Corazón son flor de azahar del naranjo, Notas marinas y jengibre; las Notas de Fondo son té, almizcle y ámbar.', 'unisex', '[{"size":"5ml","price":6900},{"size":"100ml","price":68600}]'::jsonb, '["/images/products/ARMAF%20ODYSSEY%20LIMONI.jpg","/images/products/LATTAFA%20ODYSSEY%20LIMONI.jpg","/images/products/ODYSSEY%20LIMONI(1).jpg"]'::jsonb, 15),
  ('17', 'ODYSSEY MANDARIN SKY EDP 100ML', 'ARMAF', 'Odyssey Mandarin Sky de Armaf es una fragancia de la familia olfativa para Hombres. Odyssey Mandarin Sky se lanzó en 2023. Las Notas de Salida son mandarina, naranja, azafrán y salvia; las Notas de Corazón son caramelo, haba tonka y cempasúchil (tagete, clavelón); las Notas de Fondo son ambroxan, cedro y vetiver.', 'masculino', '[{"size":"5ml","price":7700},{"size":"100ml","price":77200}]'::jsonb, '["/images/products/ARMAF%20ODYSSEY%20MANDARIN%20SKY.jpg","/images/products/ODYSSEY%20MANDARIN%20SKY.JPG"]'::jsonb, 16),
  ('18', 'VENTANA MARINE EDP 100ML', 'ARMAF', 'Ventana Marine de Armaf es una fragancia de la familia olfativa Amaderada Acuática para Hombres y Mujeres. Las Notas de Salida son naranja siciliana, cidra, bergamota de Calabria, petit grain y cardamomo; las Notas de Corazón son jengibre, neroli de Túnez, romero, jazmín, canela y lirio de los valles (muguete); las Notas de Fondo son té chino, sándalo, palisandro y madera de gaiac.', 'unisex', '[{"size":"5ml","price":8600},{"size":"100ml","price":85700}]'::jsonb, '["/images/products/Ventana%20marine(1).jpg","/images/products/Ventana%20marine(2).jpg","/images/products/Ventana%20marine(3).jpg"]'::jsonb, 17),
  ('19', 'STRONGER WITH YOU INTENSELY EDP 100ML', 'ARMANI', 'Emporio Armani Stronger With You Intensely de Giorgio Armani es una fragancia de la familia olfativa Oriental Fougère para Hombres. Emporio Armani Stronger With You Intensely se lanzó en 2019. Las Notas de Salida son pimienta rosa, enebro y violeta; las Notas de Corazón son tófe, canela, lavanda y salvia; las Notas de Fondo son vainilla, ámbar, haba tonka y gamuza.', 'masculino', '[{"size":"5ml","price":26200},{"size":"100ml","price":291500}]'::jsonb, '["/images/products/ChatGPT%20Image%2014%20jun%202026%2003_06_34%20p.m.png"]'::jsonb, 18),
  ('20', 'ANDALEEB EDP 100ML', 'ASDAAF', 'Al Andaleeb de Asdaaf es una fragancia de la familia olfativa Chipre Floral para Hombres y Mujeres. Las Notas de Salida son naranja, bergamota y mandarina; las Notas de Corazón son jazmín y rosa; las Notas de Fondo son pachulí, sándalo y vetiver.', 'femenino', '[{"size":"5ml","price":5100},{"size":"100ml","price":50600}]'::jsonb, '["/images/products/ASDAAF%20ANDALEEB(1).jpg","/images/products/ASDAAF%20ANDALEEB(2).jpg","/images/products/ASDAAF%20ANDALEEB.jpg"]'::jsonb, 19),
  ('21', 'LIQUID BRUN 100ML', 'FRENCH AVENUE', 'Liquid Brun de French Avenue es una fragancia de la familia olfativa Amaderada para Hombres. Liquid Brun se lanzó en 2024. Las Notas de Salida son canela, flor de azahar del naranjo, cardamomo y bergamota; las Notas de Corazón son vainilla Bourbon y elemí; las Notas de Fondo son praliné, ambroxan, almizcle y madera de gaiac.', 'masculino', '[{"size":"5ml","price":12400},{"size":"100ml","price":124300}]'::jsonb, '["/images/products/ChatGPT%20Image%2014%20jun%202026%2001_48_20%20p.m.png"]'::jsonb, 20),
  ('22', 'KING EDP 100ML', 'BHARARA', 'King de Bharara es una fragancia de la familia olfativa Aromática para Hombres. King se lanzó en 2021. Las Notas de Salida son naranja, bergamota y limón (lima ácida); la Nota de Corazón es notas afrutadas; las Notas de Fondo son vainilla, almizcle blanco y ámbar.', 'masculino', '[{"size":"5ml","price":13700},{"size":"100ml","price":137200}]'::jsonb, '[]'::jsonb, 21),
  ('23', 'VIKING BEIRUT EDP 100ML', 'BHARARA', 'Viking Beirut de Bharara es una fragancia de la familia olfativa Aromática para Hombres y Mujeres. Esta fragrancia es nueva. Viking Beirut se lanzó en 2024. Las Notas de Salida son bergamota, limón (lima ácida) y gálbano; las Notas de Corazón son notas ozónicas, salvia y geranio; las Notas de Fondo son pachulí, vetiver, musgo de roble y haba tonka.', 'masculino', '[{"size":"5ml","price":13700},{"size":"100ml","price":137200}]'::jsonb, '["/images/products/BHARARA%20VIKING(1).JPG","/images/products/BHARARA%20VIKING(2).jpg","/images/products/BHARARA%20VIKING(3).jpg"]'::jsonb, 22),
  ('24', 'FATTAH 100ML', 'DAR EL WARD', '', 'masculino', '[{"size":"5ml","price":8200},{"size":"100ml","price":82300}]'::jsonb, '["/images/products/ChatGPT%20Image%2014%20jun%202026%2002_29_04%20p.m.png"]'::jsonb, 23),
  ('25', 'HAWAS FOR HIM EDP 100ML', 'RASASI', 'Hawas for Him de Rasasi es una fragancia de la familia olfativa Aromática Acuática para Hombres. Hawas for Him se lanzó en 2015. Las Notas de Salida son manzana, bergamota, limón (lima ácida) y canela; las Notas de Corazón son notas acuosas, ciruela, flor de azahar del naranjo y cardamomo; las Notas de Fondo son ámbar gris, almizcle, pachulí y trozos de madera a la deriva.', 'masculino', '[{"size":"5ml","price":7000},{"size":"100ml","price":70400}]'::jsonb, '["/images/products/HAWAS%20FOR%20HIM(1).jpg","/images/products/HAWAS%20FOR%20HIM(2).jpg","/images/products/HAWAS%20FOR%20HIM.jpg"]'::jsonb, 24),
  ('26', 'LE BEAU EDT 125ml', 'JEAN PAUL GAULTIER', 'Le Beau de Jean Paul Gaultier es una fragancia de la familia olfativa Amaderada Aromática para Hombres. Le Beau se lanzó en 2019. Le Beau fue creada por Quentin Bisch y Sonia Constant. La Nota de Salida es bergamota; la Nota de Corazón es coco; la Nota de Fondo es haba tonka.', 'masculino', '[{"size":"5ml","price":15900}]'::jsonb, '[]'::jsonb, 25),
  ('27', 'LE MALE ELIXIR PARFUM 125ML', 'JEAN PAUL GAULTIER', 'Le Male Elixir de Jean Paul Gaultier es una fragancia de la familia olfativa Oriental Fougère para Hombres. Le Male Elixir se lanzó en 2023. La Nariz detrás de esta fragrancia es Quentin Bisch. Las Notas de Salida son lavanda y menta; las Notas de Corazón son vainilla y benjuí; las Notas de Fondo son miel, haba tonka y tabaco.', 'masculino', '[{"size":"5ml","price":20600}]'::jsonb, '["/images/products/JPG%20LE%20MALE%20ELIXIR%202.jpg","/images/products/JPG%20LE%20MALE%20ELIXIR.JPG"]'::jsonb, 26),
  ('28', 'LE MALE LE PARFUM 125ML', 'JEAN PAUL GAULTIER', 'Le Male Le Parfum de Jean Paul Gaultier es una fragancia de la familia olfativa Oriental para Hombres. Le Male Le Parfum se lanzó en 2020. Le Male Le Parfum fue creada por Quentin Bisch y Natalie Gracia-Cetto. La Nota de Salida es cardamomo; las Notas de Corazón son lavanda y iris; las Notas de Fondo son vainilla, notas orientales y notas amaderadas.', 'masculino', '[{"size":"5ml","price":16200}]'::jsonb, '["/images/products/JPG%20LE%20MALE%20LE%20PARFUM%202.JPG","/images/products/JPG%20LE%20MALE%20LE%20PARFUM.jpg"]'::jsonb, 27),
  ('29', 'INVICTUS VICTORY ELIXIR PARFUM 100ML', 'RABANNE', 'Invictus Victory Elixir de Rabanne es una fragancia de la familia olfativa Oriental Amaderada para Hombres. Invictus Victory Elixir se lanzó en 2023. Invictus Victory Elixir fue creada por Domitille Michalon Bertier, Anne Flipo y Nicolas Beaulieu. Las Notas de Salida son lavanda, cardamomo y pimienta negra; las Notas de Corazón son incienso y pachulí; las Notas de Fondo son vaina de vainilla y haba tonka.', 'masculino', '[{"size":"5ml","price":21300}]'::jsonb, '["/images/products/486b4780-1e33-46b8-949e-590f523e2e41.png"]'::jsonb, 28),
  ('30', 'AL NOBLE SAFEER EDP 100ML', 'LATTAFA', 'Safeer de Lattafa Perfumes es una fragancia de la familia olfativa para Hombres y Mujeres. Las Notas de Salida son toronja (pomelo), bergamota, jengibre y pimienta negra; las Notas de Corazón son caramelo, jazmín y heliotropo; las Notas de Fondo son madera de gaiac, almizcle, cipriol (nagarmota), ámbar gris y cachemira.', 'unisex', '[{"size":"5ml","price":5800},{"size":"100ml","price":58300}]'::jsonb, '["/images/products/AL%20NOBLE%20SAAFER(1).jpg","/images/products/AL%20NOBLE%20SAAFER(2).jpg","/images/products/AL%20NOBLE%20SAAFER(3).jpg"]'::jsonb, 29),
  ('31', 'QAED AL FURSAN EDP 90ml', 'LATTAFA', 'Qaed Al Fursan de Lattafa Perfumes es una fragancia de la familia olfativa Oriental Amaderada para Hombres y Mujeres. Qaed Al Fursan se lanzó en 2016. Las Notas de Salida son piña y azafrán; las Notas de Corazón son abeto balsámico y jazmín; las Notas de Fondo son cedro, ámbar y madera de oud.', 'unisex', '[{"size":"5ml","price":5300},{"size":"100ml","price":53200}]'::jsonb, '["/images/products/ChatGPT%20Image%2014%20jun%202026%2001_47_01%20p.m.png"]'::jsonb, 30),
  ('32', 'QAED AL FURSAN UNLIMITED EDP 90ml', 'LATTAFA', 'Qaed Al Fursan Unlimited de Lattafa Perfumes es una fragancia de la familia olfativa Floral Frutal Gourmand para Hombres y Mujeres. Qaed Al Fursan Unlimited se lanzó en 2022. Las Notas de Salida son coco, piña y cítricos; las Notas de Corazón son ylang-ylang, frangipani (plumeria, plumaria, atapaima) y jazmín; las Notas de Fondo son vainilla, almizcle, sándalo y notas dulces.', 'unisex', '[{"size":"5ml","price":4300},{"size":"100ml","price":42800}]'::jsonb, '["/images/products/ChatGPT%20Image%2014%20jun%202026%2001_47_27%20p.m.png"]'::jsonb, 31),
  ('33', 'BADE’E AL OUD AMETHYST EDP 100ML', 'LATTAFA', 'Bade’e Al Oud Amethyst de Lattafa Perfumes es una fragancia de la familia olfativa Oriental Vainilla para Hombres y Mujeres. Bade’e Al Oud Amethyst se lanzó en 2021. Las Notas de Salida son pimienta rosa y bergamota; las Notas de Corazón son rosa turca, rosa de Bulgaria (rosa Damascena de Bulgaria) y jazmín; las Notas de Fondo son madera de oud, ámbar y vainilla.', 'unisex', '[{"size":"5ml","price":6300},{"size":"100ml","price":62600}]'::jsonb, '["/images/products/BADEE%20AMESTHYST(1).jpg","/images/products/BADEE%20AMESTHYST(2).jpg","/images/products/BADEE%20AMESTHYST.jpg"]'::jsonb, 32),
  ('34', 'BADE’E AL OUD FOR GLORY EDP 100ML', 'LATTAFA', 'Bade’e Al Oud Oud for Glory de Lattafa Perfumes es una fragancia de la familia olfativa Oriental Amaderada para Hombres y Mujeres. Bade’e Al Oud Oud for Glory se lanzó en 2020. Las Notas de Salida son azafrán, nuez moscada y lavanda; las Notas de Corazón son madera de oud y pachulí; las Notas de Fondo son madera de oud, pachulí y almizcle.', 'masculino', '[{"size":"5ml","price":6100},{"size":"100ml","price":60800}]'::jsonb, '["/images/products/BADEE%20FOR%20GLORY(1).jpg","/images/products/BADEE%20FOR%20GLORY(2).JPG","/images/products/BADEE%20FOR%20GLORY(3).JPG"]'::jsonb, 33),
  ('35', 'BADE’E AL OUD HONOR & GLORY EDP 100ML', 'LATTAFA', 'Bade’e Al Oud Honor & Glory de Lattafa Perfumes es una fragancia de la familia olfativa para Hombres y Mujeres. Bade’e Al Oud Honor & Glory se lanzó en 2023. Las Notas de Salida son piña y créme brulée; las Notas de Corazón son canela, cúrcuma (azafrán de la India), pimienta negra y benjuí; las Notas de Fondo son vainilla, sándalo, cachemira y musgo.', 'unisex', '[{"size":"5ml","price":6100},{"size":"100ml","price":60800}]'::jsonb, '["/images/products/BADEE%20HONOR%20%26%20GLORY.JPG","/images/products/BADEEE%20HONOR%20%26%20GLORY(1).jpg","/images/products/BADEEE%20HONOR%20%26%20GLORY(2).jpg"]'::jsonb, 34),
  ('36', 'BADE’E AL OUD NOBLE BLUSH EDP 100ML', 'LATTAFA', 'Badee Al Oud Noble Blush de Lattafa Perfumes es una fragancia de la familia olfativa Floral Frutal Gourmand para Mujeres. Badee Al Oud Noble Blush se lanzó en 2024. La Nota de Salida es Leche de rosas; las Notas de Corazón son merengue y almendra; las Notas de Fondo son vainilla, sándalo y almizcle.', 'femenino', '[{"size":"5ml","price":5800},{"size":"100ml","price":58300}]'::jsonb, '["/images/products/BADEE%20NOBLE%20BLUSH(1).jpg","/images/products/BADEE%20NOBLE%20BLUSH(2).JPG","/images/products/BADEE%20NOBLE%20BLUSH(3).jpg"]'::jsonb, 35),
  ('37', 'BADE’E AL OUD SUBLIME EDP 100ML', 'LATTAFA', 'Bade’e Al Oud Sublime de Lattafa Perfumes es una fragancia de la familia olfativa Amaderada Aromática para Hombres y Mujeres. Bade’e Al Oud Sublime se lanzó en 2023. Las Notas de Salida son manzana, lichi y rosa; las Notas de Corazón son ciruela y jazmín; las Notas de Fondo son musgo, vainilla y pachulí.', 'unisex', '[{"size":"5ml","price":6100},{"size":"100ml","price":60800}]'::jsonb, '["/images/products/BADEE%20SUBLIME(1).jpg","/images/products/BADEE%20SUBLIME(2).JPG","/images/products/BADEE%20SUBLIME(3).jpg"]'::jsonb, 36),
  ('38', 'ECLAIRE EDP 100ML', 'LATTAFA', 'Eclaire de Lattafa Perfumes es una fragancia de la familia olfativa Floral Frutal Gourmand para Mujeres. Eclaire se lanzó en 2024. Las Notas de Salida son caramelo, leche y azúcar; las Notas de Corazón son miel y flores blancas; las Notas de Fondo son vainilla, praliné y almizcle.', 'femenino', '[{"size":"5ml","price":7000},{"size":"100ml","price":70300}]'::jsonb, '["/images/products/ECLAIRE(1).jpg","/images/products/ECLAIRE(2).jpg","/images/products/ECLAIRE(3).jpg"]'::jsonb, 37),
  ('39', 'EMEER EDP 100ML', 'LATTAFA', 'Emeer de Lattafa Perfumes es una fragancia de la familia olfativa Amaderada Aromática para Hombres y Mujeres. Emeer se lanzó en 2024. Las Notas de Salida son limón (lima ácida), bergamota, esclarea y bayas de enebro; las Notas de Corazón son té Blanco, sándalo, cardamomo y incienso de olíbano (franquincienso); las Notas de Fondo son ámbar gris, cedro, cachemira y pachulí.', 'unisex', '[{"size":"5ml","price":9400},{"size":"100ml","price":94300}]'::jsonb, '["/images/products/EMEER(1).jpg","/images/products/EMEER(2).jpg","/images/products/EMEER(3).jpg"]'::jsonb, 38),
  ('40', 'FAKHAR BLACK EDP 100ML', 'LATTAFA', 'Fakhar Black de Lattafa Perfumes es una fragancia de la familia olfativa Oriental para Hombres. Fakhar Black se lanzó en 2022. Las Notas de Salida son manzana, bergamota y jengibre; las Notas de Corazón son lavanda, salvia, bayas de enebro y geranio; las Notas de Fondo son haba tonka, cedro, Amberwood y vetiver.', 'masculino', '[{"size":"5ml","price":7900},{"size":"100ml","price":78800}]'::jsonb, '["/images/products/FAKHAR%20BLACK(1).jpg","/images/products/FAKHAR%20BLACK(2).jpg","/images/products/FAKHAR%20BLACK(3).JPG"]'::jsonb, 39),
  ('41', 'FAKHAR EXTRAIT EDP 100ML', 'LATTAFA', 'Fakhar Extrait de Lattafa Perfumes es una fragancia de la familia olfativa para Hombres. Fakhar Extrait se lanzó en 2023. Las Notas de Salida son toronja (pomelo), cardamomo y pimienta rosa; las Notas de Corazón son nardos, notas solares y abrótano; las Notas de Fondo son ámbar, cachemira, cuero y ládano.', 'masculino', '[{"size":"5ml","price":5800},{"size":"100ml","price":57500}]'::jsonb, '["/images/products/FAKHAR%20EXTRAIT(1).jpg","/images/products/FAKHAR%20EXTRAIT(2).jpg","/images/products/FAKHAR%20EXTRAIT(3).jpg"]'::jsonb, 40),
  ('42', 'FAKHAR WOMAN EDP 100ML', 'LATTAFA', 'Fakhar Rose de Lattafa Perfumes es una fragancia de la familia olfativa Floral para Mujeres. Fakhar Rose se lanzó en 2022. Las Notas de Salida son frutas, azucena, granada y aldehídos; las Notas de Corazón son nardos, jazmín, gardenia, ylang-ylang, rosa, madreselva y peonía; las Notas de Fondo son vainilla, almizcle blanco, sándalo y ambroxan.', 'femenino', '[{"size":"5ml","price":8400},{"size":"100ml","price":84000}]'::jsonb, '["/images/products/FAKHAR%20WOMAN(1).jpg","/images/products/FAKHAR%20WOMAN(2).jpg","/images/products/FAKHAR%20WOMAN(3).jpg"]'::jsonb, 41),
  ('43', 'HAYA EDP 100ML', 'LATTAFA', 'Haya de Lattafa Perfumes es una fragancia de la familia olfativa para Mujeres. Haya se lanzó en 2022. Las Notas de Salida son fresa, champaña, naranja tangerina, naranja sanguina y rosa; las Notas de Corazón son gardenia, jazmín y orquídea de vainilla; las Notas de Fondo son ámbar, sándalo y castaña.', 'femenino', '[{"size":"5ml","price":6700},{"size":"100ml","price":66800}]'::jsonb, '["/images/products/LATTAFA%20HAYA%202.jpg","/images/products/LATTAFA%20HAYA%204(1).jpg","/images/products/LATTAFA%20HAYA%204.JPG"]'::jsonb, 42),
  ('44', 'HAYAATI GOLD ELIXIR EDP 100ML', 'LATTAFA', 'Hayaati Gold Elixir de Lattafa Perfumes es una fragancia de la familia olfativa para Hombres y Mujeres. Las Notas de Salida son bergamota, toronja (pomelo) y casis (grosellero negro); las Notas de Corazón son cuero, durazno (melocotón) y azafrán; las Notas de Fondo son vainilla, ámbar, almizcle y vetiver.', 'unisex', '[{"size":"5ml","price":4600},{"size":"100ml","price":46300}]'::jsonb, '["/images/products/LATTAFA%20HAYAATI(1).jpg","/images/products/LATTAFA%20HAYAATI(2).jpg","/images/products/LATTAFA%20HAYAATI(3).jpg"]'::jsonb, 43),
  ('45', 'KHAMRAH EDP 100ML', 'LATTAFA', 'Khamrah de Lattafa Perfumes es una fragancia de la familia olfativa Oriental Especiada para Hombres y Mujeres. Khamrah se lanzó en 2022. Las Notas de Salida son canela, nuez moscada y bergamota; las Notas de Corazón son dátiles, praliné, nardos y Mahonial; las Notas de Fondo son vainilla, haba tonka, Amberwood, mirra, benjuí y Akigalawood.', 'unisex', '[{"size":"5ml","price":6900},{"size":"100ml","price":68600}]'::jsonb, '["/images/products/LATTAFA%20KHAMRAH(1).JPG","/images/products/LATTAFA%20KHAMRAH(2).jpg","/images/products/LATTAFA%20KHAMRAH(3).jpg"]'::jsonb, 44),
  ('46', 'MAAHIR BLACK EDP 100ML', 'LATTAFA', 'Maahir Black Edition de Lattafa Perfumes es una fragancia de la familia olfativa Oriental Especiada para Hombres y Mujeres. Maahir Black Edition se lanzó en 2020. Las Notas de Salida son pimienta negra, pimienta rosa y azafrán; las Notas de Corazón son Aceite de cade, ládano, bálsamo de Gurjum y ruibarbo; las Notas de Fondo son cuero, cedro, madera de gaiac, pachulí, musgo y almizcle.', 'masculino', '[{"size":"5ml","price":6500},{"size":"100ml","price":65200}]'::jsonb, '["/images/products/MAHIIR%20BLACK(1).jpg","/images/products/MAHIIR%20BLACK.JPG"]'::jsonb, 45),
  ('47', 'MAAHIR GOLD EDP 100ML', 'LATTAFA', 'Maahir de Lattafa Perfumes es una fragancia de la familia olfativa Oriental Floral para Hombres y Mujeres. Maahir se lanzó en 2019. Las Notas de Salida son bayas rojas, durazno (melocotón) y bergamota; las Notas de Corazón son jazmín, peonía y azucena roja; las Notas de Fondo son sándalo, flor de vainilla y almizcle.', 'unisex', '[{"size":"5ml","price":7000},{"size":"100ml","price":69500}]'::jsonb, '["/images/products/MAHIIR%20GOLD(1).jpg","/images/products/MAHIIR%20GOLD.jpg","/images/products/MAHIR%20GOLD.JPG"]'::jsonb, 46),
  ('48', 'MAYAR CHERRY INTENSE 100ML', 'LATTAFA', 'Mayar Cherry Intense de Lattafa Perfumes es una fragancia de la familia olfativa Oriental Vainilla para Hombres y Mujeres. Esta fragrancia es nueva. Mayar Cherry Intense se lanzó en 2024. Las Notas de Salida son fresa y bergamota; las Notas de Corazón son Mermelada de cereza y cacao; las Notas de Fondo son vainilla, ámbar y pachulí.', 'femenino', '[{"size":"5ml","price":6500},{"size":"100ml","price":65200}]'::jsonb, '["/images/products/LATTAFA%20MAYAR%20CHERRY.jpg","/images/products/MAYAR%20CHERRY.jpg"]'::jsonb, 47),
  ('49', 'MAYAR EDP 100ML', 'LATTAFA', 'Mayar de Lattafa Perfumes es una fragancia de la familia olfativa Floral Frutal para Mujeres. Mayar se lanzó en 2022. Las Notas de Salida son lichi, frambuesa y hojas de violeta; las Notas de Corazón son rosa blanca, peonía y jazmín; las Notas de Fondo son almizcle y vainilla.', 'femenino', '[{"size":"5ml","price":6700},{"size":"100ml","price":66800}]'::jsonb, '["/images/products/LATTAFA%20MAYAR.jpg","/images/products/MAYAR(1).jpg","/images/products/MAYAR.JPG"]'::jsonb, 48),
  ('50', 'MUSK CANDY ROSE EDP 100ML', 'LATTAFA', 'Musk Candy Rose de Lattafa Perfumes es una fragancia de la familia olfativa para Hombres y Mujeres. Musk Candy Rose se lanzó durante la 2020''s. Las Notas de Salida son rosa y cítricos; las Notas de Corazón son almizcle blanco y notas florales; las Notas de Fondo son almizcle y ámbar.', 'femenino', '[{"size":"5ml","price":5200},{"size":"100ml","price":51500}]'::jsonb, '["/images/products/LATTAFA%20CANDY%20MUSK(1).JPG","/images/products/LATTAFA%20CANDY%20MUSK.jpg"]'::jsonb, 49),
  ('51', 'SEHR EDP 100ML', 'LATTAFA', 'Sehr de Lattafa Perfumes es una fragancia de la familia olfativa Oriental Floral para Hombres y Mujeres. Sehr se lanzó en 2024. Las Notas de Salida son almendra amarga y canela; las Notas de Corazón son Akigalawood, Pomarose y jazmín; las Notas de Fondo son absoluto de vainilla, haba tonka y ámbar.', 'unisex', '[{"size":"5ml","price":8200},{"size":"100ml","price":82300}]'::jsonb, '["/images/products/ChatGPT%20Image%2014%20jun%202026%2002_36_16%20p.m.png"]'::jsonb, 50),
  ('52', 'THE KINGDOM FOR MEN EDP 100ML', 'LATTAFA', 'The Kingdom For Men de Lattafa Perfumes es una fragancia de la familia olfativa Aromática para Hombres. Esta fragrancia es nueva. The Kingdom For Men se lanzó en 2024. Las Notas de Salida son lavanda, menta y salvia; las Notas de Corazón son vainilla, tabaco y flor de azahar del naranjo; las Notas de Fondo son haba tonka, benjuí y ládano.', 'masculino', '[{"size":"5ml","price":8200},{"size":"100ml","price":82300}]'::jsonb, '["/images/products/LATTAFA%20THE%20KINGDOM.jpg","/images/products/THE%20KINGDOM(1).jpg","/images/products/THE%20KINGDOM(2).jpg"]'::jsonb, 51),
  ('53', 'VINTAGE RADIO 100ML', 'LATTAFA', 'Vintage Radio de Lattafa Perfumes es una fragancia de la familia olfativa Oriental Amaderada para Hombres y Mujeres. Vintage Radio se lanzó en 2023. Las Notas de Salida son lavanda, salvia y bergamota; las Notas de Corazón son ciruela, palo santo y pimienta negra; las Notas de Fondo son sándalo y madera de oud.', 'unisex', '[{"size":"5ml","price":6700},{"size":"100ml","price":66800}]'::jsonb, '["/images/products/ChatGPT%20Image%2014%20jun%202026%2001_48_06%20p.m.png"]'::jsonb, 52),
  ('54', 'ASAD EDP 100ML', 'LATTAFA', 'Asad de Lattafa Perfumes es una fragancia de la familia olfativa Oriental para Hombres. Asad se lanzó en 2021. Las Notas de Salida son pimienta negra, tabaco y piña; las Notas de Corazón son pachulí, café y iris; las Notas de Fondo son vainilla, ámbar, Madera seca, benjuí y ládano.', 'masculino', '[{"size":"5ml","price":7600},{"size":"100ml","price":75500}]'::jsonb, '["/images/products/LATTAFA%20ASAD(1).jpg","/images/products/LATTAFA%20ASAD.JPG"]'::jsonb, 53),
  ('55', 'ASAD BOURBON EDP 100ML', 'LATTAFA', 'Asad Bourbon de Lattafa Perfumes es una fragancia de la familia olfativa Oriental Especiada para Hombres. Esta fragrancia es nueva. Asad Bourbon se lanzó en 2025. Las Notas de Salida son lavanda, ciruela Mirabel y pimienta rosa; las Notas de Corazón son cacao, nuez moscada y Davana; las Notas de Fondo son vainilla Bourbon, ámbar y vetiver.', 'masculino', '[{"size":"5ml","price":8200},{"size":"100ml","price":82300}]'::jsonb, '["/images/products/BOURBON(1).jpg","/images/products/BOURBON.JPG","/images/products/LATTAFA%20ASAD%20BOURBON.JPG"]'::jsonb, 54),
  ('56', 'YARA CANDY WOMAN EDP 100ML', 'LATTAFA', 'Yara Candy de Lattafa Perfumes es una fragancia de la familia olfativa Floral Frutal Gourmand para Mujeres. Esta fragrancia es nueva. Yara Candy se lanzó en 2024. Las Notas de Salida son grosellas negras y Mandarina verde; las Notas de Corazón son Caramelo de fresa efervescente y gardenia; las Notas de Fondo son vainilla, almizcle, ámbar y sándalo.', 'femenino', '[{"size":"5ml","price":6100},{"size":"100ml","price":60800}]'::jsonb, '["/images/products/YARA%20CANDY(1).JPG","/images/products/YARA%20CANDY(2).jpg","/images/products/YARA%20CANDY(3).jpg"]'::jsonb, 55),
  ('57', 'YARA MOI EDP 100ML', 'LATTAFA', 'Yara Moi de Lattafa Perfumes es una fragancia de la familia olfativa para Mujeres. Yara Moi se lanzó en 2022. Las Notas de Salida son jazmín y durazno (melocotón); las Notas de Corazón son caramelo y ámbar; las Notas de Fondo son pachulí y sándalo.', 'femenino', '[{"size":"5ml","price":6100},{"size":"100ml","price":60800}]'::jsonb, '["/images/products/YARA%20MOI(1).jpg","/images/products/YARA%20MOI(2).jpg","/images/products/YARA%20MOI.jpg"]'::jsonb, 56),
  ('58', 'YARA TOUS EDP 100ML', 'LATTAFA', 'Yara Tous de Lattafa Perfumes es una fragancia de la familia olfativa para Mujeres. Yara Tous se lanzó en 2023. Las Notas de Salida son mango, coco y maracuyá (fruta de la pasión); las Notas de Corazón son jazmín, flor de azahar del naranjo y heliotropo; las Notas de Fondo son vainilla, almizcle y cachemira.', 'femenino', '[{"size":"5ml","price":6100},{"size":"100ml","price":60800}]'::jsonb, '["/images/products/YARA%20TOUS(1).JPG","/images/products/YARA%20TOUS(2).jpg","/images/products/YARA%20TOUS(3).jpg"]'::jsonb, 57),
  ('59', 'YARA WOMAN EDP 100ML', 'LATTAFA', 'Yara de Lattafa Perfumes es una fragancia de la familia olfativa Oriental Vainilla para Mujeres. Yara se lanzó en 2020. Las Notas de Salida son orquídea, heliotropo y naranja tangerina; las Notas de Corazón son Acorde goloso y frutas tropicales; las Notas de Fondo son vainilla, almizcle y sándalo.', 'femenino', '[{"size":"5ml","price":6300},{"size":"100ml","price":62600}]'::jsonb, '["/images/products/YARA%20WOMAN(1).jpg","/images/products/YARA%20WOMAN(2).jpg","/images/products/YARA%20WOMAN.JPG"]'::jsonb, 58),
  ('60', 'CORAL BLUSH 80ML', 'MAISON ALHAMBRA', 'Coral Blush de Maison Alhambra es una fragancia de la familia olfativa Floral Frutal para Hombres y Mujeres. Esta fragrancia es nueva. Coral Blush se lanzó en 2024. Las Notas de Salida son durazno (melocotón), hojas verdes y naranja sanguina; la Nota de Corazón es pachulí; las Notas de Fondo son coñac y miel.', 'unisex', '[{"size":"5ml","price":5200},{"size":"100ml","price":51500}]'::jsonb, '["/images/products/CORAL%20BLUSH(1).jpg","/images/products/coral%20blush(2).jpg","/images/products/Coral%20blush(3).jpg"]'::jsonb, 59),
  ('61', 'JEAN LOWE OMBRE EDP 100ML', 'MAISON ALHAMBRA', 'Jean Lowe Ombre de Maison Alhambra es una fragancia de la familia olfativa para Hombres. Jean Lowe Ombre se lanzó en 2023. Las Notas de Salida son madera de oud y incienso; las Notas de Corazón son rosa, azafrán, frambuesa y abedul; las Notas de Fondo son ámbar, benjuí y geranio.', 'masculino', '[{"size":"5ml","price":6900},{"size":"100ml","price":68600}]'::jsonb, '["/images/products/JEAN%20LOWE%20NOIR(1).jpg","/images/products/JEAN%20LOWE%20NOIR.jpg"]'::jsonb, 60),
  ('62', 'PHILOS PURA EDP 100ML', 'MAISON ALHAMBRA', 'Philos Pura de Maison Alhambra es una fragancia de la familia olfativa Aromática Frutal para Hombres y Mujeres. Philos Pura se lanzó en 2022. Las Notas de Salida son naranja, bergamota y limón (lima ácida); la Nota de Corazón es frutas; las Notas de Fondo son vainilla de Madagascar, almizcle blanco y ámbar.', 'unisex', '[{"size":"5ml","price":7300},{"size":"100ml","price":73300}]'::jsonb, '["/images/products/PHILOS%20PURA(1).jpg","/images/products/PHILOS%20PURA.jpg"]'::jsonb, 61),
